func HasImageWith(preds ...predicate.Image) predicate.ProjectTask {
	return predicate.ProjectTask(func(s *sql.Selector) {
		step := newImageStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

